import { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaArrowLeft, FaTrash, FaUser, FaClock } from 'react-icons/fa';
import AuthContext from '../context/AuthContext';
import Spinner from '../components/Spinner';
import forumService from '../api/forumService';

function ForumPost() {
  const [post, setPost] = useState(null);
  const [comment, setComment] = useState('');
  const [loading, setLoading] = useState(true);

  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useContext(AuthContext);

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const data = await forumService.getForumPostById(id);
        setPost(data);
      } catch (error) {
        toast.error('Error fetching post');
        navigate('/forum');
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id, navigate]);

  const handleAddComment = async (e) => {
    e.preventDefault();

    if (!comment.trim()) {
      toast.error('Comment cannot be empty');
      return;
    }

    try {
      const updatedPost = await forumService.addComment(
        id,
        { comment },
        user.token
      );
      setPost(updatedPost);
      setComment('');
      toast.success('Comment added successfully');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to add comment');
    }
  };

  const handleDeletePost = async () => {
    if (window.confirm('Are you sure you want to delete this post?')) {
      try {
        await forumService.deleteForumPost(id, user.token);
        toast.success('Post deleted successfully');
        navigate('/forum');
      } catch (error) {
        toast.error(error.response?.data?.message || 'Failed to delete post');
      }
    }
  };

  const handleDeleteComment = async (commentId) => {
    if (window.confirm('Are you sure you want to delete this comment?')) {
      try {
        const updatedPost = await forumService.deleteComment(
          id,
          commentId,
          user.token
        );
        setPost(updatedPost);
        toast.success('Comment deleted successfully');
      } catch (error) {
        toast.error(
          error.response?.data?.message || 'Failed to delete comment'
        );
      }
    }
  };

  // Format date
  const formatDate = (dateString) => {
    const options = { year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  if (loading) {
    return <Spinner />;
  }

  if (!post) {
    return (
      <div className="text-center py-10">
        <h2 className="text-2xl font-semibold mb-4">Post not found</h2>
        <Link
          to="/forum"
          className="text-green-600 hover:text-green-800 font-medium"
        >
          Back to Forum
        </Link>
      </div>
    );
  }

  return (
    <div>
      <div className="mb-6">
        <Link
          to="/forum"
          className="text-green-600 hover:text-green-700 flex items-center"
        >
          <FaArrowLeft className="mr-2" /> Back to Forum
        </Link>
      </div>

      <div className="bg-white p-6 rounded-lg shadow-md mb-8">
        <div className="flex justify-between items-start mb-4">
          <h1 className="text-3xl font-bold text-green-700">{post.title}</h1>
          {isAuthenticated && user._id === post.user._id && (
            <button
              onClick={handleDeletePost}
              className="text-red-500 hover:text-red-700"
            >
              <FaTrash />
            </button>
          )}
        </div>

        <div className="flex items-center text-sm text-gray-500 mb-6">
          <div className="flex items-center mr-4">
            <FaUser className="mr-1" />
            <span>{post.user?.name || 'Anonymous'}</span>
          </div>
          <div className="flex items-center">
            <FaClock className="mr-1" />
            <span>{formatDate(post.createdAt)}</span>
          </div>
        </div>

        <div className="text-gray-700 mb-6 whitespace-pre-line">
          {post.description}
        </div>
      </div>

      <div className="bg-white p-6 rounded-lg shadow-md mb-8">
        <h2 className="text-2xl font-semibold text-green-700 mb-4">
          Comments ({post.comments.length})
        </h2>

        {isAuthenticated ? (
          <form onSubmit={handleAddComment} className="mb-6">
            <div className="form-group">
              <label className="block text-gray-700 mb-2" htmlFor="comment">
                Add a Comment
              </label>
              <textarea
                className="form-control h-24"
                id="comment"
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                placeholder="Write your comment here..."
                required
              ></textarea>
            </div>
            <button type="submit" className="btn btn-primary mt-2">
              Submit Comment
            </button>
          </form>
        ) : (
          <div className="bg-yellow-50 border border-yellow-200 p-4 rounded-lg mb-6">
            <p className="text-yellow-700">
              Please{' '}
              <Link to="/login" className="text-green-600 hover:underline">
                login
              </Link>{' '}
              to add a comment.
            </p>
          </div>
        )}

        {post.comments.length === 0 ? (
          <div className="text-center py-4 text-gray-500">
            No comments yet. Be the first to comment!
          </div>
        ) : (
          <div className="space-y-4">
            {post.comments.map((comment) => (
              <div
                key={comment._id}
                className="border-b border-gray-100 pb-4 last:border-0"
              >
                <div className="flex justify-between items-start mb-2">
                  <div className="flex items-center text-sm text-gray-500">
                    <FaUser className="mr-1" />
                    <span className="font-medium mr-2">
                      {comment.commenterName}
                    </span>
                    <span>{formatDate(comment.createdAt)}</span>
                  </div>
                  {isAuthenticated &&
                    (user._id === comment.commenterId ||
                      user._id === post.user._id) && (
                      <button
                        onClick={() => handleDeleteComment(comment._id)}
                        className="text-red-500 hover:text-red-700 text-sm"
                      >
                        <FaTrash />
                      </button>
                    )}
                </div>
                <p className="text-gray-700">{comment.comment}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default ForumPost;
